'use strict';
require('dotenv').config();
const mongoose = require('mongoose');
const MONGO_URI = process.env.MONGO_URI || 'mongodb://127.0.0.1:27017/travelguru';

const placeSchema = new mongoose.Schema({
  placeId:Number, name:String, state:String, city:String, category:String,
  bg:String, img:String, desc:String,
  bestTime:String, difficulty:String, nearestCity:String,
  entryFee:String, featured:Boolean, lat:Number, lng:Number,
},{ strict:false });
const Place = mongoose.model('Place', placeSchema);

const budgetSchema = new mongoose.Schema({ placeId:Number, budgetMin:Number, budgetMid:Number, budgetLux:Number, hotel:String, food:String, transport:String, idealDays:Number, notes:String },{ strict:false });
const Budget = mongoose.model('Budget', budgetSchema);

const hotelSchema = new mongoose.Schema({ placeId:Number, name:String, type:String, stars:Number, pricePerNight:String, address:String, phone:String, amenities:[String], mapLink:String },{ strict:false });
const Hotel = mongoose.model('Hotel', hotelSchema);

const restaurantSchema = new mongoose.Schema({ placeId:Number, name:String, cuisine:String, priceRange:String, rating:Number, address:String, specialty:String, timing:String },{ strict:false });
const Restaurant = mongoose.model('Restaurant', restaurantSchema);

const tipSchema = new mongoose.Schema({ placeId:Number, category:String, tip:String, priority:Number },{ strict:false });
const Tip = mongoose.model('Tip', tipSchema);

