/* ── SEED ── */
async function seed(){
  try{
    await mongoose.connect(MONGO_URI,{serverSelectionTimeoutMS:10000});
    console.log('Connected to MongoDB:', MONGO_URI);

    await Promise.all([
      Place.deleteMany({}), Budget.deleteMany({}),
      Hotel.deleteMany({}), Restaurant.deleteMany({}), Tip.deleteMany({})
    ]);
    console.log('Cleared existing data');

    const inserted = await Place.insertMany(PLACES);
    console.log(`Inserted ${inserted.length} places`);
    await Budget.insertMany(BUDGETS);
    console.log(`Inserted ${BUDGETS.length} budgets`);
    await Hotel.insertMany(HOTELS);
    console.log(`Inserted ${HOTELS.length} hotels`);
    await Restaurant.insertMany(RESTAURANTS);
    console.log(`Inserted ${RESTAURANTS.length} restaurants`);
    await Tip.insertMany(TIPS);
    console.log(`Inserted ${TIPS.length} tips`);

    const stateStats = await Place.aggregate([{$group:{_id:'$state',count:{$sum:1}}},{$sort:{_id:1}}]);
    console.log('\nPlaces by State:');
    stateStats.forEach(s=>console.log(`  ${s._id}: ${s.count} places`));
    console.log(`\nTotal: ${inserted.length} places across ${stateStats.length} states`);
    console.log('\nAdmin Login:');
    console.log('  ID:       admin@travelguru.in');
    console.log('  Password: Admin@TG2025#Secure');
    console.log('  URL:      http://localhost:8080/admin');
    process.exit(0);
  }catch(err){
    console.error('Seed failed:', err.message);
    process.exit(1);
  }
}
seed();